6	//! Focused `#[cuda_module]` host ABI contract test.
7	//!
8	//! The kernel intentionally mixes common host-side argument shapes the typed
9	//! module macro must lower correctly: scalars, slice, raw device pointer, and
10	//! `DisjointSlice` output.
11	
12	use cuda_core::{CudaContext, DeviceBuffer, LaunchConfig1D};
13	use cuda_device::{
14	    DisjointSlice, DynamicSharedArray, cuda_module, kernel, launch_bounds, launch_contract, thread,
15	};
16	
17	#[cuda_module]
18	mod kernels {
19	    use super::*;
20	
21	    #[inline(never)]
22	    fn ordinary_shared_owner(value: u32) {
23	        let shared = DynamicSharedArray::<u32, 16>::get();
24	        unsafe {
25	            core::ptr::write_volatile(shared, value);
26	        }
27	    }
28	
29	    #[inline(never)]
30	    fn ordinary_shared_forward(value: u32) {
31	        ordinary_shared_owner(value);
32	    }
33	
34	    /// Two entries share the same transitive helper. The helper's single PTX
35	    /// declaration must use the stronger contract from either caller.
36	    #[kernel]
37	    #[launch_bounds(32)]
38	    #[launch_contract(
39	        domain = 1,
40	        block = (32, 1, 1),
41	        dynamic_shared = 128,
42	        dynamic_shared_alignment = 32,
43	    )]
44	    pub fn helper_contract_32(value: u32) {
45	        ordinary_shared_forward(value);
46	    }
47	
48	    #[kernel]
49	    #[launch_bounds(32)]
50	    #[launch_contract(
51	        domain = 1,
52	        block = (32, 1, 1),
53	        dynamic_shared = 128,
54	        dynamic_shared_alignment = 256,
55	    )]
56	    pub fn helper_contract_256(value: u32) {
57	        ordinary_shared_forward(value);
58	    }
59	
60	    #[kernel]
61	    #[launch_bounds(256)]
62	    #[launch_contract(domain = 1, block = (256, 1, 1), dynamic_shared = 0)]
63	    pub fn mixed_abi(
64	        scale: f32,
65	        bias: f32,
66	        extra: f32,
67	        input: &[f32],
68	        raw_offsets: *const f32,
69	        mut output: DisjointSlice<f32>,
70	    ) {
71	        let idx = thread::index_1d();
72	        let idx_raw = idx.get();
73	        if let Some(out_elem) = output.get_mut(idx) {
74	            let offset = unsafe { *raw_offsets.add(idx_raw) };
75	            *out_elem = input[idx_raw] * scale + bias + extra + offset;
76	        }
77	    }
78	
79	    /// Compile-time proof that a contract alignment is merged with alignment
80	    /// requested by the body. The body asks for 16 bytes; the contract raises
81	    /// the emitted extern-shared declaration to 128 bytes.
82	    #[kernel]
83	    #[launch_bounds(256)]
84	    #[launch_contract(
85	        domain = 1,
86	        block = (256, 1, 1),
87	        dynamic_shared = 1024,
88	        dynamic_shared_alignment = 128,
89	    )]
90	    pub fn aligned_dynamic_shared(mut output: DisjointSlice<u8>) {
91	        let index = thread::index_1d();
92	        let linear = index.get();
93	        let shared = DynamicSharedArray::<u8, 16>::get_raw();
94	        unsafe {
95	            *shared.add(thread::threadIdx_x() as usize) = linear as u8;
96	        }
97	        if let Some(output) = output.get_mut(index) {
98	            *output = unsafe { *shared.add(thread::threadIdx_x() as usize) };
99	        }
100	    }
101	
102	    /// Generic/closure pin: the prepared brand and compiler-side alignment
103	    /// marker must both survive monomorphization onto the exported wrapper.
104	    // Deliberately put both configuration attributes above #[kernel]. They
105	    // expand into body markers before the generic entry wrapper is generated.
106	    #[launch_contract(
107	        domain = 1,
108	        block = (64, 1, 1),
109	        dynamic_shared = 256,
110	        dynamic_shared_alignment = 64,
111	    )]
112	    #[launch_bounds(64)]
113	    #[kernel]
114	    pub fn generic_aligned<F: Fn(u32) -> u32 + Copy>(op: F, mut output: DisjointSlice<u32>) {
115	        let index = thread::index_1d();
116	        let linear = index.get();
117	        let shared = DynamicSharedArray::<u32, 16>::get();
118	        unsafe {
119	            *shared.add(thread::threadIdx_x() as usize) = op(linear as u32);
120	        }
121	        if let Some(output) = output.get_mut(index) {
122	            *output = unsafe { *shared.add(thread::threadIdx_x() as usize) };
123	        }
124	    }
125	}
126	
127	/// Compile-only coverage for `#[kernel(Type)]`, the explicit-instantiation
128	/// form. Its concrete entry still calls a generic helper, so the entry's
129	/// alignment contract must propagate to the helper that owns shared memory.
130	mod explicit_instantiation {
131	    use super::*;
132	
133	    // The explicit-instantiation expansion must forward pre-expanded markers
134	    // just like the call-site monomorphization path above.
135	    #[launch_bounds(32)]
136	    #[launch_contract(
137	        domain = 1,
138	        block = (32, 1, 1),
139	        dynamic_shared = 128,
140	        dynamic_shared_alignment = 32,
141	    )]
142	    #[kernel(u32)]
143	    pub fn explicit_aligned<T: Copy>(value: T) {
144	        let shared = DynamicSharedArray::<T, 8>::get();
145	        unsafe {
146	            core::ptr::write_volatile(shared, value);
147	        }
148	    }
149	}
150	
151	fn main() -> Result<(), Box<dyn std::error::Error>> {
152	    if std::env::args().any(|arg| arg == "--verify-ptx") {
153	        return verify_launch_contract_ptx();
154	    }
155	
156	    println!("=== cuda_module ABI Contract Test ===\n");
157	
158	    let ctx = CudaContext::new(0)?;
159	    let stream = ctx.default_stream();
160	    // SAFETY: this example has one device-code owner, and `cargo oxide` builds
161	    // the merged PTX set from the `kernels` module above with no conflicting
162	    // entry definitions.
163	    let module = unsafe { kernels::load(&ctx)? };
164	
165	    const N: usize = 1024;
166	    let scale = 1.5f32;
167	    let bias = 2.0f32;
168	    let extra = 7.0f32;
169	    let input_host: Vec<f32> = (0..N).map(|i| i as f32).collect();
170	    let offset_host: Vec<f32> = (0..N).map(|i| (i % 5) as f32).collect();
171	
172	    let input_dev = DeviceBuffer::from_host(&stream, &input_host)?;
173	    let offset_dev = DeviceBuffer::from_host(&stream, &offset_host)?;
174	    let mut output_dev = DeviceBuffer::<f32>::zeroed(&stream, N)?;
175	
176	    let launch = module.prepare_mixed_abi(LaunchConfig1D::new((N as u32).div_ceil(256), 256, 0))?;
177	
178	    module.mixed_abi(
179	        &stream,
180	        &launch,
181	        scale,
182	        bias,
183	        extra,
184	        &input_dev,
185	        offset_dev.cu_deviceptr() as *const f32,
186	        &mut output_dev,
187	    )?;
188	
189	    let output = output_dev.to_host_vec(&stream)?;
190	    let errors = (0..N)
191	        .filter(|&i| {
192	            let expected = input_host[i] * scale + bias + extra + offset_host[i];
193	            (output[i] - expected).abs() > 1e-5
194	        })
195	        .count();
196	
197	    assert_eq!(errors, 0, "mixed ABI kernel produced {errors} errors");
198	
199	    let mut generic_output = DeviceBuffer::<u32>::zeroed(&stream, N)?;
200	    let add_three = |value: u32| value + 3;
201	    let generic_launch = module.prepare_generic_aligned_for(
202	        &add_three,
203	        LaunchConfig1D::new((N as u32).div_ceil(64), 64, 256),
204	    )?;
205	    module.generic_aligned(&stream, &generic_launch, add_three, &mut generic_output)?;
206	    let generic_output = generic_output.to_host_vec(&stream)?;
207	    assert!(
208	        generic_output
209	            .iter()
210	            .enumerate()
211	            .all(|(index, &value)| value == index as u32 + 3),
212	        "generic prepared launch produced an unexpected value",
213	    );
214	
215	    println!("SUCCESS: mixed ABI typed launch passed");
216	    Ok(())
217	}
218	
219	fn verify_launch_contract_ptx() -> Result<(), Box<dyn std::error::Error>> {
220	    let ptx_path =
221	        std::path::Path::new(env!("CARGO_MANIFEST_DIR")).join("cuda_module_contract.ptx");
222	    let ptx = std::fs::read_to_string(&ptx_path)?;
223	    let aligned_symbol = ".extern .shared .align 128 .b8 __dynamic_smem_aligned_dynamic_shared[];";
224	    if !ptx.contains(aligned_symbol) {
225	        return Err(format!(
226	            "{} does not contain the contract-enforced dynamic shared-memory alignment",
227	            ptx_path.display()
228	        )
229	        .into());
230	    }
231	    if !ptx.lines().any(|line| {
232	        line.contains(".extern .shared .align 64 .b8 __dynamic_smem_")
233	            && line.contains("generic_aligned")
234	    }) {
235	        return Err(
236	            "generic launch contract alignment did not reach its PTX specialization".into(),
237	        );
238	    }
239	    if !ptx.lines().any(|line| {
240	        line.contains(".extern .shared .align 32 .b8 __dynamic_smem_")
241	            && line.contains("explicit_aligned")
242	    }) {
243	        return Err("explicit generic instantiation alignment did not reach its PTX helper".into());
244	    }
245	    if !ptx.lines().any(|line| {
246	        line.contains(".extern .shared .align 256 .b8 __dynamic_smem_")
247	            && line.contains("ordinary_shared_owner")
248	    }) {
249	        return Err(
250	            "shared ordinary helper did not receive the strongest calling-kernel alignment".into(),
251	        );
252	    }
253	
254	    for entry in ["aligned_dynamic_shared", "mixed_abi"] {
255	        let start = ptx
256	            .find(&format!(".visible .entry {entry}("))
257	            .ok_or_else(|| format!("missing PTX entry {entry}"))?;
258	        let rest = &ptx[start..];
259	        let end = rest[1..]
260	            .find(".visible .entry ")
261	            .map_or(rest.len(), |offset| offset + 1);
262	        if !rest[..end].contains(".maxntid 256, 1, 1") {
263	            return Err(format!("PTX entry {entry} lost its launch bounds").into());
264	        }
265	    }
266	
267	    for entry in [
268	        "helper_contract_32",
269	        "helper_contract_256",
270	        "explicit_aligned_u32",
271	    ] {
272	        let start = ptx
273	            .find(&format!(".visible .entry {entry}("))
274	            .ok_or_else(|| format!("missing PTX entry {entry}"))?;
275	        let rest = &ptx[start..];
276	        let end = rest[1..]
277	            .find(".visible .entry ")
278	            .map_or(rest.len(), |offset| offset + 1);
279	        if !rest[..end].contains(".maxntid 32, 1, 1") {
280	            return Err(format!("PTX entry {entry} lost its launch bounds").into());
281	        }
282	    }
283	
284	    let generic_start = ptx
285	        .find(".visible .entry generic_aligned_TID_")
286	        .ok_or("missing generic_aligned PTX specialization")?;
287	    let generic_rest = &ptx[generic_start..];
288	    let generic_end = generic_rest[1..]
289	        .find(".visible .entry ")
290	        .map_or(generic_rest.len(), |offset| offset + 1);
291	    if !generic_rest[..generic_end].contains(".maxntid 64, 1, 1") {
292	        return Err("generic_aligned PTX specialization lost its launch bounds".into());
293	    }
294	
295	    println!("SUCCESS: prepared-launch PTX contract verified");
296	    Ok(())
297	}
