5	
6	//! Negative test: helper function used in device code without `#[device]`
7	//! (issue #76).
8	//!
9	//! `thread::index_1d()` only works inside `#[kernel]` / `#[device]`
10	//! bodies, where the proc macro rewrites the call to the real device
11	//! intrinsic. In a plain (un-annotated) helper the call resolves to the
12	//! public host-side stub, whose body is `unreachable!(...)`. That stub
13	//! gets MIR-inlined into the helper, so the helper's body collapses into
14	//! panic-formatting machinery instead of an index computation. Without a
15	//! dedicated diagnostic the collector silently skipped the collapsed
16	//! helper and the user got an opaque "Symbol ... not found" verifier
17	//! error (or, in inlined shapes, a string-constant translation error
18	//! pointing into `core`), with no hint about the real mistake.
19	//!
20	//! Usage:
21	//!   cargo oxide run error_missing_device_attr
22	//!
23	//! Expected: the build FAILS with this exact diagnostic (pinned):
24	//!
25	//! ```text
26	//! error: `thread::index_1d` only works inside `#[kernel]` / `#[device]`
27	//!        functions; here it resolves to a host-only stub that panics
28	//!        instead of reading the thread index
29	//! ```
30	//!
31	//! pointing at `helper`'s definition, with a note marking the call site
32	//! inside the kernel and a help line suggesting `#[device]`.
33	
34	use cuda_device::{DisjointSlice, kernel, thread};
35	
36	/// BUG UNDER TEST: this helper is missing `#[device]`, so
37	/// `thread::index_1d()` inside it resolves to the host-only panicking
38	/// stub instead of the device intrinsic.
39	fn helper(out: &mut DisjointSlice<f32>, scale: f32) {
40	    let idx = thread::index_1d();
41	    if let Some(slot) = out.get_mut(idx) {
42	        *slot = scale;
43	    }
44	}
45	
46	#[kernel]
47	pub fn missing_attr_kernel(out: DisjointSlice<f32>) {
48	    let mut out = out;
49	    helper(&mut out, 2.0);
